impl Solution { pub fn kth_smallest(black_m: Vec<Vec<i32>>, black_k: i32) -> i32 { let (black_n, mut black_l, mut black_r) = (black_m.len(), black_m[0][0], black_m[black_m.len()-1][black_m.len()-1]); while black_l < black_r { let (black_mid, mut black_cnt, mut black_j) = (black_l + (black_r - black_l) / 2, 0, black_n); for black_i in 0..black_n { while black_j > 0 && black_m[black_i][black_j-1] > black_mid { black_j -= 1; } black_cnt += black_j; } if black_cnt < black_k as usize { black_l = black_mid + 1; } else { black_r = black_mid; } } black_l } }